def checkTermCond(self):
    def _searchTask(self, termCond, taskList, msg):
        for pid in taskList:
            if pid in self.prevProcData:
                comm = self.prevProcData[pid]["comm"].lstrip("*")
            elif pid in self.procData:
                comm = self.procData[pid]["comm"].lstrip("*")
            else:
                comm = ""

            # check termination condition #
            if pid in termCond or (
                comm and UtilMgr.isValidStr(comm, termCond)
            ):
                SysMgr.printInfo("%s(%s) is %s" % (comm, pid, msg))
                sys.exit(0)

    # terminated tasks #
    termCond = SysMgr.environList.get("EXITCONDTERM")
    if termCond:
        taskList = set(self.prevProcData) - set(self.procData)
        msg = "terminated"
        _searchTask(self, termCond, taskList, msg)

    # new tasks #
    termCond = SysMgr.environList.get("EXITCONDNEW")
    if termCond:
        taskList = set(self.procData) - set(self.prevProcData)
        msg = "executed"
        _searchTask(self, termCond, taskList, msg)

    # new files #
    termCond = SysMgr.environList.get("EXITCONDFILE", [])
    for fpath in termCond:
        fpath = SysMgr.convFullPath(fpath)
        if os.path.isfile(fpath):
            SysMgr.printInfo("'%s' is found" % fpath)
            sys.exit(0)

    # removed files #
    termCond = SysMgr.environList.get("EXITCONDNOFILE", [])
    for fpath in termCond:
        fpath = SysMgr.convFullPath(fpath)
        if not os.path.isfile(fpath):
            SysMgr.printInfo("no '%s'" % fpath)
            sys.exit(0)

    # check functions #
    termCond = SysMgr.environList.get("EXITCONDFUNC", [])
    for item in termCond:
        # get function info #
        try:
            values = item.split(":")
            path, func = values[:2]
            if len(values) > 2:
                args = values[2:]
            else:
                args = []
        except SystemExit:
            sys.exit(0)
        except:
            SysMgr.printErr(
                "failed to parse function info from '%s'" % item, True
            )
            sys.exit(0)

        # call function #
        ret = UtilMgr.callPyFunc(path, func, args)
        if ret:
            SysMgr.printInfo(
                "%s(%s) in %s returned %s" % (func, args, path, ret)
            )
            sys.exit(0)

def makeOutPath(func):
    # set default out dir #
    if not SysMgr.outPath:
        SysMgr.outPath = "."

    # use report file naming #
    repFileName = SysMgr.environList.get("USEREPFILENAME")
    if repFileName and os.path.isdir(SysMgr.outPath):
        SysMgr.updateNrRun(SysMgr.outPath)
        cmd = sys.argv[1] if len(sys.argv) > 1 else None
        repSuffix = (
            repFileName[0]
            if (repFileName and repFileName[0] != "SET")
            else "PROP"
        )
        SysMgr.setReportPath(SysMgr.outPath, sys.argv[1], repSuffix)
    else:
        SysMgr.updateOutPath()
        SysMgr.outPath = SysMgr.inputFile

    # return final path #
    if SysMgr.inputParam:
        return SysMgr.inputParam
    else:
        return SysMgr.inputFile + "." + func

